module top_module (
    input [1:0] s,
    output reg obf_a
);

    always @(*) begin
        case (s)
            2'b00: obf_a = 0;
            2'b01: obf_a = 1;
            2'b10: obf_a = 1;
            2'b11: obf_a = 0;
            default: obf_a = 0; // Default case
        endcase
    end
endmodule
